var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이쪽은 어느 정도 정리된 것 같군요.","JPN":"こちらはある程度片付いたようですね。","ENG":"It looks like we are done here.","TWN":"這裡應該處理得差不多了。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응…… 하지만 걱정이네.","JPN":"うん……でも心配だな。","ENG":"Yes... But something worries me.","TWN":"嗯……不過真令人擔心。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"오는 길에 잠깐 뉴스를 봤는데 또 침식 현상이 재발했다는 모양이야.","JPN":"ここに来る途中にちょっとニュースを見たんだけど、また侵食現象が再発したらしいよ。","ENG":"I saw the news on the way here, they say there’s another Counterside Effect going on.","TWN":"我來的路上有看到新聞，似乎又發生侵蝕現象。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키라면 친구들을 잘 지켜줄 거라 믿지만……","JPN":"雅紀ならみんなをちゃんと守ってくれていると思うけど……","ENG":"I trust Masaki to protect my friends, but...","TWN":"雖然我相信雅紀會保護好同學……"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"이상하군요. 이 정도 규모의 침식재난이 이틀 연속해서 일어나다니.","JPN":"おかしいですね。この規模の侵食災害が二日も続けて起きるとは。","ENG":"Strange. A Corruption disaster this big occurring two days in a row...?","TWN":"奇怪，竟然連續二天發生這種規模的侵蝕災難。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그러게. 게다가 보통 침식 쐐기가 같은 장소에 자라나는 경우는 거의 없는데 말이지.","JPN":"そうだね。それに普通侵食楔が同じ場所に生えてくる場合はほとんどないのに。","ENG":"I know, right? It’s even rarer for Corrupted Wedges to grow in the same place.","TWN":"就是說，而且通常侵蝕釘不會長在同一個地方的。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"같은 장소…… 말입니까?","JPN":"同じ場所……ですか？","ENG":"They grew up in the same place...?","TWN":"同一個地方……嗎？"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"노아라는 이름의 신생 태스크포스입니다. 침식이 재발하지 않도록 침식 쐐기를 제거하는 뒤처리 전문반이죠.","JPN":"ノアという新生タスクフォースです。侵食が再発しないように侵食楔を取り除く、いわば後始末の専門班ですね。","ENG":"They are a new TASKFORCE called NOA. They are in charge of destroying the Corrupted Wedges, so that the disaster doesn’t happen again.","TWN":"他們是新興的特遣勢力，叫作諾亞，專門負責清除侵蝕釘，以防再次發生侵蝕事件。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"필요한 작업은 전부 끝났다. 돌아가자.","JPN":"必要な作業はすべて終わった。帰るぞ。","ENG":"We have done everything that needs to be done. Come.","TWN":"事情辦得差不多了，回去吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공, 저는 지금 가봐야 할 곳이 생겼습니다.","JPN":"奈由香殿、私は行くべきところができました。","ENG":"I must get going, Mr. Nayuka.","TWN":"南裕夏，我現在要去一個地方。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 도움이 필요한 거지? 나도 같이 갈게.","JPN":"あ、助けが必要なんだよね？　僕も一緒に行くよ。","ENG":"Oh, you need help? I’ll come with.","TWN":"需要幫忙嗎？我也一起去。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"조금 늦긴 했지만, 나도 가문연합의 일원이잖아?","JPN":"ちょっと遅くなったけど、僕も連合の一員だからね。","ENG":"It’s a little late, but I am part of the Alliance after all.","TWN":"雖然現在才說這些有點遲，不過我也是家族聯盟的一員嘛？"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"나유카 공은 한결 같이 좋은 사람이군요.","JPN":"奈由香殿は相変わらずいい方ですね。","ENG":"You are a good person, Mr. Nayuka.","TWN":"南裕夏，你還是一樣人那麼好。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇기 때문에, 공께선 스스로가 지키고 싶은 사람들을 위해 남아 주셨으면 합니다.","JPN":"だからこそ、あなたには守るべき人のために残っていただきたいのです。","ENG":"Which is why I wish you would stay here and protect the people that you care for.","TWN":"所以我希望你留在這裡保護你重視的人。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저는 당주님의 호위로서, 제 소명을 다할 테니까요.","JPN":"私は当主の護衛として、自分の使命を果たします。","ENG":"I will serve my duty protecting Lady Nanahara.","TWN":"我身為堂主的護衛，有我該盡的職責。"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MYEONGDONG_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"비상상황이다! 관리국 호송 차량이 신원미상의 적들에게 공격받고 있다! 지원을……!","JPN":"非常状態だ！　管理局の護送車両が身元不明の敵に攻撃されている！　支援を……！","ENG":"Mayday! Mayday! Transport vehicles under attack! Enemy unidentified! Requesting support...!","TWN":"緊急狀況！管理局護送車隊受到身分不明的人士攻擊！請求支……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"}]`);export{e as default};